const fs=require('fs');
const journal=JSON.parse(fs.readFileSync('drizzle/meta/_journal.json','utf8'));
const s31=JSON.parse(fs.readFileSync('drizzle/meta/0031_snapshot.json','utf8'));
const s32=JSON.parse(fs.readFileSync('drizzle/meta/0032_snapshot.json','utf8'));
const s33=JSON.parse(fs.readFileSync('drizzle/meta/0033_snapshot.json','utf8'));
const entries=journal.entries;
const lastTwo=entries.slice(-2);
const checks=[
  ['last two tags', JSON.stringify(lastTwo.map(e=>e.tag))===JSON.stringify(['0032_credit_brain_clock_fields','0033_credit_account_completeness_fields'])],
  ['idx continuity', lastTwo[0].idx===32 && lastTwo[1].idx===33],
  ['0032 prevId matches 0031 id', s32.prevId===s31.id],
  ['0033 prevId matches 0032 id', s33.prevId===s32.id],
  ['snapshot versions', s32.version==='7' && s33.version==='7'],
];
for (const [name, ok] of checks) console.log(`${ok?'PASS':'FAIL'}: ${name}`);
process.exit(checks.every(([,ok])=>ok)?0:1);
